const get = (key) => {
  const v = $json[key];
  return v !== undefined && v !== null ? v : '';
};

function normaliseNewsTopicCode(value) {
  const raw = String(value || '').trim().toLowerCase();

  const cleaned = raw
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');

  const map = {
    obituary: 'obituary',
    in_memoriam: 'obituary',
    memorial: 'obituary',

    restitution: 'restitution',
    repatriation: 'restitution',

    auction_result: 'auction_result',
    auction_results: 'auction_result',
    sale_result: 'auction_result',

    auction_announcement: 'auction_announcement',
    auction: 'auction_announcement',
    sale: 'auction_announcement',

    award: 'award',
    awards: 'award',
    prize: 'award',
    prizes: 'award',
    honour: 'award',
    honor: 'award',

    exhibition: 'exhibition_announcement',
    exhibition_announcement: 'exhibition_announcement',
    show: 'exhibition_announcement',

    representation: 'representation_deal',
    representation_deal: 'representation_deal',
    gallery_representation: 'representation_deal',

    appointment: 'appointment',
    role_change: 'appointment',
    new_role: 'appointment',
    director_appointment: 'appointment',

    firing: 'firing',
    resignation: 'firing',
    departure: 'firing',

    gallery_opening: 'gallery_opening',
    gallery_expansion: 'gallery_opening',
    opening: 'gallery_opening',

    gallery_closure: 'gallery_closure',
    gallery_closing: 'gallery_closure',
    closure: 'gallery_closure',

    legal: 'legal',
    lawsuit: 'legal',
    lawsuits: 'legal',
    policy: 'legal',
    court: 'legal',

    archaeology: 'archaeology',
    discovery: 'archaeology',
    archaeological_discovery: 'archaeology',

    other: 'other',
  };

  return map[cleaned] || 'other';
}

function makeSlug(value) {
  return String(value || '')
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 160);
}

const title =
  $json.baad_title ||
  get('BAAD Title') ||
  get('SEO Title') ||
  get('Title') ||
  '';

const dek =
  $json.baad_dek ||
  get('BAAD Dek') ||
  get('Dek') ||
  get('Editor Summary') ||
  '';

const body =
  $json.baad_body ||
  get('Body (BAAD Draft)') ||
  get('Source Body / Summary') ||
  '';

const newsTopicCode = normaliseNewsTopicCode(
  get('News Topic Code') ||
  get('News Topic') ||
  'other'
);

const existingSlug =
  get('Strapi Slug') ||
  get('Slug') ||
  '';

const idSuffix = String($json.airtableId || $json.id || Date.now())
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '')
  .slice(-6);

let slug = existingSlug || makeSlug(title || get('Title') || 'article');

if (!slug) {
  slug = `article-${idSuffix || Date.now()}`;
} else if (!existingSlug && idSuffix) {
  slug = `${slug}-${idSuffix}`;
}

const strapiDocumentId =
  get('Strapi Document ID') ||
  get('Strapi Article ID') ||
  '';

return {
  json: {
    ...$json,
    airtableId: $json.airtableId || $json.id,
    strapiDocumentId,
    strapiSlug: slug,
    strapiPayload: {
      title,
      slug,
      dek,
      body,
      newsTopicCode,
      tags: [],
    },
  },
};

const sourceItems = $items('Build Strapi Payload');
const sourceItem = sourceItems[$itemIndex];

if (!sourceItem) {
  throw new Error(`Could not find matching item from Build Strapi Payload for itemIndex=${$itemIndex}`);
}

const original = sourceItem.json;

const found = Array.isArray($json.data) ? $json.data[0] : null;

return {
  json: {
    ...original,

    existingStrapiId: found?.id || null,
    existingStrapiDocumentId: found?.documentId || null,
    existingStrapiSlug: found?.slug || null,

    // true means update existing Strapi article
    // false means create a new Strapi article
    shouldUpdate: !!found,
  },
};
